module johnson_counter (
    input clk,
    input reset,
    output reg [5:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (reset) begin
            count <= 6'b0;
        end else begin
            count <= {~count[0], count[5:1]};
        end
    end

endmodule
